SELECT SUM(confirmed) AS total_confirmed_cases
FROM covid_data
WHERE region_id = 1;

SELECT AVG(confirmed) AS average_confirmed_cases
FROM covid_data
WHERE confirmed > 1000;

SELECT SUM(confirmed) AS total_confirmed_cases
FROM covid_data
WHERE last_update = (
    SELECT MAX(last_update)
    FROM covid_data
);

SELECT region_id, MAX(confirmed) as max_confirmed_cases
FROM covid_data
GROUP BY region_id;

SELECT confirmed, deaths
FROM covid_data
WHERE region_id = 1;

SELECT region_id
FROM covid_data
WHERE confirmed = (SELECT MAX(confirmed) FROM covid_data);
